    public int magicalString(int n) {
        if (n == 0) return 0;
        if (n <= 3) return 1;
        int[] s = new int[n];
        s[0] = 1;
        s[1] = 2;
        s[2] = 2;
        int idx = 2;
        int tail = 3;
        int count = 1;
        while (tail < n) {
            int size = s[idx];
            int num = 3 - s[tail - 1];
